import { Type, Exact, TPlutusData } from "@blaze-cardano/data";
type Data = Exact<typeof TPlutusData>;
type Int = bigint;
type ByteArray = string;
const PolicyId = Type.String();
type OutputReference = { output_index: bigint; transaction_id: string };

const Contracts = Type.Module({
  AuthoritySetCommitment: Type.Object({
    id: Type.BigInt(),
    len: Type.BigInt(),
    root: Type.String(),
  }, { ctor: 0n }),
  BeefyConsensusState: Type.Object({
    latest_height: Type.BigInt(),
    beefy_activation_block: Type.BigInt(),
    current_authority_set: Type.Ref("AuthoritySetCommitment"),
    current_stake_total: Type.BigInt(),
    next_authority_set: Type.Ref("AuthoritySetCommitment"),
    next_stake_total: Type.BigInt(),
  }, { ctor: 0n }),
  BeefyMmrLeaf: Type.Object({
    version: Type.BigInt(),
    parent_number: Type.BigInt(),
    parent_hash: Type.String(),
    next_authority_set: Type.Ref("AuthoritySetCommitment"),
    extra: Type.String(),
    k_index: Type.BigInt(),
    leaf_index: Type.BigInt(),
  }, { ctor: 0n }),
  Commitment: Type.Object({
    payloads: Type.Array(
      Type.Ref("Payload")
    ),
    block_number: Type.BigInt(),
    validator_set_id: Type.BigInt(),
  }, { ctor: 0n }),
  Payload: Type.Object({
    id: Type.String(),
    data: Type.String(),
  }, { ctor: 0n }),
  ProofNodeRec: Type.Array(
    TPlutusData
  ),
  SignedCommitment: Type.Object({
    commitment: Type.Ref("Commitment"),
    votes: Type.Array(
      Type.Ref("Vote")
    ),
  }, { ctor: 0n }),
  Vote: Type.Object({
    signature: Type.String(),
    authority_index: Type.BigInt(),
    public_key: Type.String(),
    vote_strength: Type.BigInt(),
  }, { ctor: 0n }),
  DustAction: Type.Union([
    Type.Literal("Create", { ctor: 0n }),
    Type.Literal("Burn", { ctor: 1n }),
  ]),
  DustMappingDatum: Type.Object({
    c_wallet: Type.Union([
      Type.Object({
        VerificationKey: Type.Tuple([
          Type.String(),
        ], { ctor: 0n })
      }),
      Type.Object({
        Script: Type.Tuple([
          Type.String(),
        ], { ctor: 1n })
      }),
    ]),
    dust_address: Type.String(),
  }, { ctor: 0n }),
  CandidateKey: Type.Tuple([
    Type.String(),
    Type.String(),
  ]),
  FederatedOps: Type.Tuple([
    TPlutusData,
    Type.Array(
      Type.Ref("PermissionedCandidateDatumV1")
    ),
    Type.BigInt(),
  ]),
  PermissionedCandidateDatumV1: Type.Tuple([
    Type.Ref("SidechainPublicKey"),
    Type.Array(
      Type.Ref("CandidateKey")
    ),
  ]),
  SidechainPublicKey: Type.String(),
  TermsAndConditions: Type.Tuple([
    Type.String(),
    Type.String(),
  ]),
  MultisigThreshold: Type.Tuple([
    Type.BigInt(),
    Type.BigInt(),
    Type.BigInt(),
    Type.BigInt(),
  ]),
  Sr25519PubKey: Type.String(),
  TwoStageRedeemer: Type.Tuple([
    Type.Ref("UpdateField"),
    Type.Ref("WhichStage"),
  ]),
  UpdateField: Type.Union([
    Type.Literal("Logic", { ctor: 0n }),
    Type.Literal("Auth", { ctor: 1n }),
    Type.Literal("MitigationLogic", { ctor: 2n }),
    Type.Literal("MitigationAuth", { ctor: 3n }),
  ]),
  UpgradeState: Type.Tuple([
    Type.String(),
    Type.String(),
    Type.String(),
    Type.String(),
    Type.BigInt(),
    Type.BigInt(),
  ]),
  WhichStage: Type.Union([
    Type.Object({
      Main: Type.Tuple([
        Type.Object({
          transaction_id: Type.String(),
          output_index: Type.BigInt(),
        }, { ctor: 0n }),
      ], { ctor: 0n })
    }),
    Type.Object({
      Staging: Type.Tuple([
        Type.Object({
          transaction_id: Type.String(),
          output_index: Type.BigInt(),
        }, { ctor: 0n }),
        Type.String(),
      ], { ctor: 1n })
    }),
  ]),
  Multisig: Type.Tuple([
    Type.BigInt(),
    Type.Record(
      Type.String(),
      Type.Ref("Sr25519PubKey"),
    ),
  ]),
  PermissionedRedeemer: Type.Record(
    Type.String(),
    Type.Ref("Sr25519PubKey"),
  ),
  RelayChainProof: Type.Object({
    signed_commitment: Type.Ref("SignedCommitment"),
    latest_mmr_leaf: Type.Ref("BeefyMmrLeaf"),
    proof: Type.Ref("ProofNodeRec"),
  }, { ctor: 0n }),
  VersionedMultisig: Type.Tuple([
    Type.Ref("Multisig"),
    Type.BigInt(),
  ]),
  VersionedTermsAndConditions: Type.Tuple([
    Type.Ref("TermsAndConditions"),
    Type.BigInt(),
  ]),
});

